SELECT COUNT(*)
FROM bids
WHERE bidder_id = 0;

SELECT MAX(bid_amount) AS highest_bid
FROM bids
WHERE auction_id = 1;

SELECT first_name, last_name, bid_count AS total_bids
FROM bidders
ORDER BY bid_count DESC;

SELECT first_name, last_name
FROM bidders
WHERE bid_count > 3 AND credit_score >= 70;

SELECT COUNT(bidder_id) AS total_bidders
FROM bidders
WHERE bid_count > 0;

SELECT bid_count
FROM bidders
ORDER BY bid_count DESC;

SELECT bid_amount, bid_time
FROM bids
ORDER BY bid_time DESC;
